(()=>{window.JM_RECOLOR_DATA=Object.assign(window.JM_RECOLOR_DATA||{},{"buzz/jacket/academy":"","buzz/jacket/explorer":"","buzz/jacket/haori":"","buzz/pants/black":"","buzz/pants/denim":"","buzz/pants/khaki":"","buzz/pants/purple":"","buzz/pants/red":""});window.getJapaneseMinerRecolor=window.getJapaneseMinerRecolor||((hair,part,id)=>{const value=window.JM_RECOLOR_DATA[hair+'/'+part+'/'+id];return value?'url("data:image/webp;base64,'+value+'")':'none';});})();
